package com.socialblog.notification.api;import com.socialblog.notification.domain.Notification;import com.socialblog.notification.repository.NotificationRepository;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.test.web.servlet.MockMvc;import java.time.Instant;import java.util.UUID;import static org.springframework.security.test.web.servlet.request.SecurityMockMvcRequestPostProcessors.jwt;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@SpringBootTest @AutoConfigureMockMvc class NotificationControllerIntegrationTest{@Autowired MockMvc mvc;@Autowired NotificationRepository notifications;@Test void listUnreadAndReadOperationsAreRecipientScoped()throws Exception{UUID user=UUID.randomUUID(),other=UUID.randomUUID(),actor=UUID.randomUUID();Notification first=notifications.save(new Notification(UUID.randomUUID(),user,actor,Notification.Type.NEW_FOLLOWER,"USER",actor,"{}",Instant.now()));notifications.save(new Notification(UUID.randomUUID(),user,actor,Notification.Type.NEW_COMMENT,"COMMENT",UUID.randomUUID(),"{}",Instant.now()));notifications.save(new Notification(UUID.randomUUID(),other,actor,Notification.Type.NEW_LIKE,"ARTICLE",UUID.randomUUID(),"{}",Instant.now()));mvc.perform(get("/api/v1/notifications").with(jwt().jwt(j->j.subject(user.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.content.length()").value(2));mvc.perform(get("/api/v1/notifications/unread-count").with(jwt().jwt(j->j.subject(user.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.count").value(2));mvc.perform(patch("/api/v1/notifications/"+first.getId()+"/read").with(jwt().jwt(j->j.subject(user.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.readAt").isNotEmpty());mvc.perform(patch("/api/v1/notifications/"+first.getId()+"/read").with(jwt().jwt(j->j.subject(other.toString())))).andExpect(status().isNotFound());mvc.perform(patch("/api/v1/notifications/read-all").with(jwt().jwt(j->j.subject(user.toString())))).andExpect(status().isOk()).andExpect(jsonPath("$.count").value(0));}@Test void endpointsRequireAuthentication()throws Exception{mvc.perform(get("/api/v1/notifications")).andExpect(status().isUnauthorized());}@Test void standardizesListAndPathErrors()throws Exception{UUID user=UUID.randomUUID();mvc.perform(get("/api/v1/notifications?page=-1").with(jwt().jwt(j->j.subject(user.toString())))).andExpect(status().isBadRequest()).andExpect(jsonPath("$.code").value("INVALID_PAGE")).andExpect(jsonPath("$.path").value("/api/v1/notifications"));mvc.perform(patch("/api/v1/notifications/not-a-uuid/read").with(jwt().jwt(j->j.subject(user.toString())))).andExpect(status().isBadRequest()).andExpect(jsonPath("$.code").value("INVALID_REQUEST_PARAMETER")).andExpect(jsonPath("$.fields.id").isNotEmpty());}}
